// ─── Write files ───
function writeJson(filePath, data) {
  const dir = path.dirname(filePath);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n', 'utf8');
  console.log(`  wrote: ${path.relative(BASE_DIR, filePath)}`);
}

// 1. Write project.json files
console.log('=== Writing project.json files ===');
for (const proj of projects) {
  const projDir = path.join(BASE_DIR, proj.contextPath);
  writeJson(path.join(projDir, 'project.json'), {
    configId: proj.configId,
    name: proj.name,
    type: proj.type,
    contextPath: proj.contextPath,
    description: proj.description
  });
}

// 2. Write workflow/agent JSON files
console.log('\n=== Writing workflow/agent JSON files ===');
let workflowCount = 0;
let agentCount = 0;

for (const wf of allWorkflows) {
  const contextPath = projectIdToContext[wf.projectId];
  if (!contextPath) {
    console.log(`  SKIP: ${wf.name} (unknown projectId: ${wf.projectId})`);
    continue;
  }

  const isAgent = agentIds.has(wf.id);
  const configId = toKebab(wf.name);
  const wfDir = path.join(BASE_DIR, contextPath, 'workflows');

  const configFile = {
    configId: configId,
    name: wf.name,
    description: wf.description,
    type: isAgent ? 'AGENT' : 'WORKFLOW',
    nodes: wf.nodes,
    connections: wf.connections
  };

  // Include icon for agents
  if (isAgent && wf.icon) {
    configFile.icon = wf.icon;
  }

  writeJson(path.join(wfDir, configId + '.json'), configFile);

  if (isAgent) agentCount++;
  else workflowCount++;
}

console.log(`\n=== DONE ===`);
console.log(`Projects:  ${projects.length}`);
console.log(`Workflows: ${workflowCount}`);
console.log(`Agents:    ${agentCount}`);
console.log(`Total:     ${workflowCount + agentCount}`);
